import React, { useState, useCallback, useMemo } from "react";
import axios from "axios";
import "./App.css";
import IndividualAnalysis from "./IndividualAnalysis";
import BatchAnalysis from "./BatchAnalysis";
import HistoryPanel from "./HistoryPanel";
import ExportResults from "./ExportResults";

const API_BASE = "http://localhost:5000/api";

// Enhanced default data with validation ranges
const DEFAULT_CUSTOMER_DATA = {
  Tenure: { value: 5.0, min: 0, max: 60, step: 0.1 },
  OrderCount: { value: 5.0, min: 0, max: 100, step: 1 },
  CashbackAmount: { value: 12000.0, min: 0, max: 50000, step: 100 },
  DaySinceLastOrder: { value: 7.0, min: 0, max: 365, step: 1 },
  HourSpendOnApp: { value: 30.0, min: 0, max: 24, step: 0.1 },
  OrderAmountHikeFromlastYear: { value: 15.0, min: -100, max: 500, step: 0.1 },
  CouponUsed: { value: 1, min: 0, max: 50, step: 1 },
  NumberOfDeviceRegistered: { value: 3, min: 1, max: 10, step: 1 },
  Complain: { value: 0, options: [0, 1] },
  SatisfactionScore: { value: 3, min: 1, max: 5, step: 1 },
  WarehouseToHome: { value: 10.0, min: 1, max: 100, step: 1 },
  NumberOfAddress: { value: 4, min: 1, max: 20, step: 1 },
  CityTier: { value: 1, options: [1, 2, 3] },
  PreferredLoginDevice: { value: "Mobile Phone", options: ["Mobile Phone", "Computer", "Phone", "Tablet"] },
  PreferredPaymentMode: { value: "Credit Card", options: ["Credit Card", "Debit Card", "UPI", "Net Banking", "Cash on Delivery", "E-Wallet"] },
  PreferedOrderCat: { value: "Laptop & Accessory", options: ["Laptop & Accessory", "Mobile & Accessory", "Grocery", "Fashion", "Electronics", "Beauty", "Books"] },
  Gender: { value: "Male", options: ["Male", "Female", "Other"] },
  MaritalStatus: { value: "Married", options: ["Married", "Single", "Divorced", "Widowed"] },
};

function App() {
  const [mode, setMode] = useState("individual");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [results, setResults] = useState(null);
  const [batchResults, setBatchResults] = useState(null);
  const [batchFile, setBatchFile] = useState(null);
  const [customerData, setCustomerData] = useState(() => 
    Object.fromEntries(
      Object.entries(DEFAULT_CUSTOMER_DATA).map(([key, config]) => [key, config.value])
    )
  );
  const [analysisHistory, setAnalysisHistory] = useState([]);
  const [showHistory, setShowHistory] = useState(false);

  // Memoized mode description
  const modeDescription = useMemo(() => {
    return mode === "individual" 
      ? "Analyze churn probability for individual customers with detailed insights and historical tracking"
      : "Process multiple customers at once with CSV file upload and comprehensive batch analytics";
  }, [mode]);

  // Enhanced mode change handler
  const handleModeChange = useCallback((newMode) => {
    setMode(newMode);
    setResults(null);
    setBatchResults(null);
    setError(null);
    setShowHistory(false);
  }, []);

  // Enhanced reset with confirmation
  const handleResetForm = useCallback(() => {
    if (window.confirm("Are you sure you want to reset all fields to default values?")) {
      const resetData = Object.fromEntries(
        Object.entries(DEFAULT_CUSTOMER_DATA).map(([key, config]) => [key, config.value])
      );
      setCustomerData(resetData);
      setResults(null);
      setError(null);
    }
  }, []);

  // Add to history
  const addToHistory = useCallback((data, result, type = "individual") => {
    const historyEntry = {
      id: Date.now(),
      timestamp: new Date().toISOString(),
      type,
      data,
      result,
      summary: type === "individual" ? {
        churnRisk: result.prediction ? "High" : "Low",
        probability: result.probability,
        customerId: `CUST-${Date.now().toString().slice(-6)}`
      } : {
        totalProcessed: result.total_records,
        churnCount: result.churn_count,
        churnRate: result.churn_rate
      }
    };

    setAnalysisHistory(prev => [historyEntry, ...prev.slice(0, 49)]); // Keep last 50 entries
  }, []);

  // Load from history
  const loadFromHistory = useCallback((historyEntry) => {
    if (historyEntry.type === "individual") {
      setCustomerData(historyEntry.data);
      setResults(historyEntry.result);
      setMode("individual");
      setShowHistory(false);
    }
  }, []);

  // Enhanced individual analysis
  const handleIndividualAnalyze = async () => {
    setLoading(true);
    setError(null);

    // Client-side validation
    const validationError = validateCustomerData(customerData);
    if (validationError) {
      setError(validationError);
      setLoading(false);
      return;
    }

    try {
      const res = await axios.post(`${API_BASE}/individual`, customerData, {
        timeout: 15000,
      });

      const enhancedResults = {
        ...res.data,
        timestamp: new Date().toISOString(),
        inputData: { ...customerData }
      };

      setResults(enhancedResults);
      addToHistory(customerData, enhancedResults, "individual");
    } catch (err) {
      const errorMessage = getErrorMessage(err);
      setError(errorMessage);
      console.error("Analysis error:", err);
    } finally {
      setLoading(false);
    }
  };

  // Enhanced batch analysis
  const handleBatchAnalyze = async () => {
    if (!batchFile) {
      setError("Please select a CSV file first");
      return;
    }

    // Validate file type
    if (!batchFile.name.toLowerCase().endsWith('.csv')) {
      setError("Please upload a CSV file");
      return;
    }

    setLoading(true);
    setError(null);
    const formData = new FormData();
    formData.append("file", batchFile);

    try {
      const res = await axios.post(`${API_BASE}/batch`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
        timeout: 60000, // 60 seconds for batch processing
        onUploadProgress: (progressEvent) => {
          // Could add progress bar here
          console.log('Upload progress:', progressEvent.loaded / progressEvent.total);
        }
      });

      const enhancedResults = {
        ...res.data,
        timestamp: new Date().toISOString(),
        fileName: batchFile.name
      };

      setBatchResults(enhancedResults);
      addToHistory({ fileName: batchFile.name }, enhancedResults, "batch");
    } catch (err) {
      const errorMessage = getErrorMessage(err);
      setError(errorMessage);
      console.error("Batch analysis error:", err);
    } finally {
      setLoading(false);
    }
  };

  // Utility functions
  const validateCustomerData = (data) => {
    const requiredFields = ['Tenure', 'OrderCount', 'CashbackAmount', 'SatisfactionScore'];
    const missingFields = requiredFields.filter(field => !data[field] && data[field] !== 0);

    if (missingFields.length > 0) {
      return `Missing required fields: ${missingFields.join(', ')}`;
    }

    if (data.SatisfactionScore < 1 || data.SatisfactionScore > 5) {
      return "Satisfaction Score must be between 1 and 5";
    }

    if (data.HourSpendOnApp < 0 || data.HourSpendOnApp > 24) {
      return "Hours spent on app must be between 0 and 24";
    }

    return null;
  };

  const getErrorMessage = (error) => {
    if (error.code === 'ECONNABORTED') {
      return "Request timeout. Please try again.";
    }
    if (error.response?.status === 413) {
      return "File too large. Please upload a smaller file.";
    }
    if (error.response?.data?.message) {
      return error.response.data.message;
    }
    if (error.message.includes('Network Error')) {
      return "Network error. Please check your connection and try again.";
    }
    return "An unexpected error occurred. Please try again.";
  };

  return (
    <div className="app-wrapper">
      <header className="top-header">
        <div className="header-content">
          <h1 className="project-title">
            <span className="title-icon">📊</span>
            Customer <span>Churn Intelligence</span>
          </h1>

          <div className="header-actions">
            <button 
              className="history-btn"
              onClick={() => setShowHistory(!showHistory)}
              title="View Analysis History"
            >
              📋 History
            </button>
          </div>
        </div>

        <div className="mode-toggle">
          <button
            className={`mode-btn ${mode === "individual" ? "active" : ""}`}
            onClick={() => handleModeChange("individual")}
          >
            📊 Individual Analysis
          </button>
          <button
            className={`mode-btn ${mode === "batch" ? "active" : ""}`}
            onClick={() => handleModeChange("batch")}
          >
            📁 Batch Analysis
          </button>
        </div>

        <p className="mode-description">
          {modeDescription}
        </p>
      </header>

      <main className="dashboard futuristic-bg">
        {/* Error Display */}
        {error && (
          <div className="error-banner">
            <span className="error-icon">⚠️</span>
            <span className="error-message">{error}</span>
            <button onClick={() => setError(null)} className="close-error">×</button>
          </div>
        )}

        {/* Loading Overlay */}
        {loading && (
          <div className="loading-overlay">
            <div className="loading-spinner"></div>
            <p>Processing your request...</p>
            {mode === "batch" && <p className="loading-subtext">This may take a few moments</p>}
          </div>
        )}

        <div className="main-content">
          {/* History Panel */}
          {showHistory && (
            <HistoryPanel
              history={analysisHistory}
              onLoadEntry={loadFromHistory}
              onClose={() => setShowHistory(false)}
              onClearHistory={() => setAnalysisHistory([])}
            />
          )}

          {/* Main Analysis Components */}
          <div className={`analysis-container ${showHistory ? 'with-history' : ''}`}>
            {mode === "individual" ? (
              <IndividualAnalysis
                customerData={customerData}
                onInputChange={setCustomerData}
                onAnalyze={handleIndividualAnalyze}
                onReset={handleResetForm}
                loading={loading}
                results={results}
                error={error}
                fieldConfig={DEFAULT_CUSTOMER_DATA}
              />
            ) : (
              <BatchAnalysis
                onFileChange={(e) => {
                  setBatchFile(e.target.files[0]);
                  setError(null);
                  setBatchResults(null);
                }}
                onAnalyze={handleBatchAnalyze}
                loading={loading}
                results={batchResults}
                selectedFile={batchFile}
              />
            )}

            {/* Export Results */}
            {(results || batchResults) && (
              <ExportResults
                results={results || batchResults}
                type={mode}
                customerData={mode === "individual" ? customerData : null}
              />
            )}
          </div>
        </div>
      </main>

      {/* Footer */}
      <footer className="app-footer">
        <div className="footer-content">
          <p>Customer Churn Intelligence Platform v1.2.0</p>
          <div className="footer-links">
            <button className="footer-link">Documentation</button>
            <button className="footer-link">Support</button>
            <button className="footer-link">Feedback</button>
          </div>
        </div>
      </footer>
    </div>
  );
}

export default App;
